import React, { useState, useEffect, createContext, useContext } from 'react';
import { BrowserRouter, Routes, Route, Link, Navigate, useNavigate } from 'react-router-dom';
import axios from 'axios';
import './App.css';

// API Config
const API_URL = 'http://localhost:5000/api';
const api = axios.create({ baseURL: API_URL });

api.interceptors.request.use(config => {
    const token = localStorage.getItem('token');
    if (token) config.headers.Authorization = `Bearer ${token}`;
    return config;
});

// ==================== Auth Context ====================
const AuthContext = createContext();
const useAuth = () => useContext(AuthContext);

const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const token = localStorage.getItem('token');
        if (token) {
            api.get('/auth/me')
                .then(res => setUser(res.data.user))
                .catch(() => localStorage.removeItem('token'))
                .finally(() => setLoading(false));
        } else {
            setLoading(false);
        }
    }, []);

    const login = async (email, password) => {
        const res = await api.post('/auth/login', { email, password });
        localStorage.setItem('token', res.data.token);
        setUser(res.data.user);
    };

    const register = async (email, password, name) => {
        const res = await api.post('/auth/register', { email, password, name });
        localStorage.setItem('token', res.data.token);
        setUser(res.data.user);
    };

    const logout = () => {
        localStorage.removeItem('token');
        setUser(null);
    };

    return (
        <AuthContext.Provider value={{ user, login, register, logout, loading }}>
            {children}
        </AuthContext.Provider>
    );
};

// ==================== Login Page ====================
const Login = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const { login } = useAuth();
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            await login(email, password);
            navigate('/');
        } catch (err) {
            setError(err.response?.data?.message || 'Login failed');
        }
    };

    return (
        <div className="auth-container">
            <div className="auth-card">
                <div className="auth-header">
                    <div className="logo">🏥</div>
                    <h1>Disease Predictor</h1>
                    <p>AI-Powered Health Analysis</p>
                </div>
                <form onSubmit={handleSubmit}>
                    {error && <div className="error">{error}</div>}
                    <input
                        type="email"
                        placeholder="Email"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        required
                    />
                    <input
                        type="password"
                        placeholder="Password"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        required
                    />
                    <button type="submit" className="btn-primary">Login</button>
                </form>
                <p className="auth-link">
                    Don't have an account? <Link to="/register">Register</Link>
                </p>
            </div>
        </div>
    );
};

// ==================== Register Page ====================
const Register = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [name, setName] = useState('');
    const [error, setError] = useState('');
    const { register } = useAuth();
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            await register(email, password, name);
            navigate('/');
        } catch (err) {
            setError(err.response?.data?.message || 'Registration failed');
        }
    };

    return (
        <div className="auth-container">
            <div className="auth-card">
                <div className="auth-header">
                    <div className="logo">🏥</div>
                    <h1>Create Account</h1>
                </div>
                <form onSubmit={handleSubmit}>
                    {error && <div className="error">{error}</div>}
                    <input
                        type="text"
                        placeholder="Full Name"
                        value={name}
                        onChange={(e) => setName(e.target.value)}
                        required
                    />
                    <input
                        type="email"
                        placeholder="Email"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        required
                    />
                    <input
                        type="password"
                        placeholder="Password (min 6 characters)"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        required
                        minLength={6}
                    />
                    <button type="submit" className="btn-primary">Register</button>
                </form>
                <p className="auth-link">
                    Already have an account? <Link to="/login">Login</Link>
                </p>
            </div>
        </div>
    );
};

// ==================== Symptom Checker ====================
const SymptomChecker = () => {
    const [symptoms, setSymptoms] = useState([]);
    const [availableSymptoms, setAvailableSymptoms] = useState([]);
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedSymptoms, setSelectedSymptoms] = useState([]);
    const [loading, setLoading] = useState(false);
    const [result, setResult] = useState(null);

    useEffect(() => {
        api.get('/symptoms').then(res => {
            setAvailableSymptoms(res.data.symptoms || []);
        });
    }, []);

    const filteredSymptoms = availableSymptoms.filter(s =>
        s.toLowerCase().includes(searchTerm.toLowerCase()) &&
        !selectedSymptoms.includes(s)
    );

    const addSymptom = (symptom) => {
        setSelectedSymptoms([...selectedSymptoms, symptom]);
        setSearchTerm('');
    };

    const removeSymptom = (symptom) => {
        setSelectedSymptoms(selectedSymptoms.filter(s => s !== symptom));
    };

    const handlePredict = async () => {
        if (selectedSymptoms.length === 0) {
            alert('Please select at least one symptom');
            return;
        }

        setLoading(true);
        try {
            const res = await api.post('/predict', { symptoms: selectedSymptoms });
            setResult(res.data);
        } catch (err) {
            alert(err.response?.data?.message || 'Prediction failed');
        } finally {
            setLoading(false);
        }
    };

    if (result) {
        return <ResultsDisplay result={result} onReset={() => { setResult(null); setSelectedSymptoms([]); }} />;
    }

    return (
        <div className="checker-container">
            <div className="card">
                <h2>🔍 Symptom Checker</h2>
                <p className="subtitle">Select your symptoms for AI-powered diagnosis</p>

                <div className="search-box">
                    <input
                        type="text"
                        placeholder="🔎 Search symptoms..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                    {searchTerm && (
                        <div className="symptom-dropdown">
                            {filteredSymptoms.slice(0, 10).map(symptom => (
                                <div
                                    key={symptom}
                                    className="symptom-option"
                                    onClick={() => addSymptom(symptom)}
                                >
                                    {symptom.replace(/_/g, ' ')}
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                <div className="selected-symptoms">
                    <p><strong>Selected Symptoms ({selectedSymptoms.length}):</strong></p>
                    <div className="chips">
                        {selectedSymptoms.map(symptom => (
                            <div key={symptom} className="chip">
                                {symptom.replace(/_/g, ' ')}
                                <button onClick={() => removeSymptom(symptom)}>×</button>
                            </div>
                        ))}
                    </div>
                </div>

                <button
                    className="btn-primary"
                    onClick={handlePredict}
                    disabled={loading || selectedSymptoms.length === 0}
                >
                    {loading ? 'Analyzing...' : '🔬 Predict Disease'}
                </button>
            </div>
        </div>
    );
};

// ==================== Results Display ====================
const ResultsDisplay = ({ result, onReset }) => {
    const final = result.final_prediction;
    const rf = result.rf_prediction;
    const knn = result.knn_prediction;
    const info = result.disease_info;

    const getConfidenceColor = (level) => {
        switch (level) {
            case 'High': return '#10b981';
            case 'Medium': return '#f59e0b';
            case 'Low': return '#ef4444';
            default: return '#6b7280';
        }
    };

    return (
        <div className="results-container">
            <div className="result-card main-result">
                <div className="result-header">
                    <div>
                        <p className="result-label">Final Prediction</p>
                        <h1>{final.disease}</h1>
                        <p className="model-used">Model: {final.model_used}</p>
                    </div>
                    <div className="confidence-badge" style={{ backgroundColor: getConfidenceColor(final.confidence_level) }}>
                        <div className="confidence-value">{final.confidence.toFixed(1)}%</div>
                        <div className="confidence-label">{final.confidence_level}</div>
                    </div>
                </div>
            </div>

            <div className="card">
                <h3>📋 Disease Information</h3>
                <p className="description">{info.description}</p>

                <h4>🛡️ Recommended Precautions:</h4>
                <ul className="precautions">
                    {info.precautions.map((prec, idx) => (
                        <li key={idx}>{prec}</li>
                    ))}
                </ul>
            </div>

            <div className="model-comparison">
                <div className="card model-card">
                    <h4>🌲 Random Forest</h4>
                    <p className="disease-name">{rf.disease}</p>
                    <p className="confidence">{rf.confidence.toFixed(1)}%</p>
                    <div className="top-predictions">
                        <small>Top 3 Predictions:</small>
                        {rf.top_5.slice(0, 3).map((p, idx) => (
                            <div key={idx} className="prediction-item">
                                <span>{p.disease}</span>
                                <span>{p.probability.toFixed(1)}%</span>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="card model-card">
                    <h4>🎯 KNN Model</h4>
                    <p className="disease-name">{knn.disease}</p>
                    <p className="confidence">{knn.confidence.toFixed(1)}%</p>
                    <div className="top-predictions">
                        <small>Top 3 Predictions:</small>
                        {knn.top_5.slice(0, 3).map((p, idx) => (
                            <div key={idx} className="prediction-item">
                                <span>{p.disease}</span>
                                <span>{p.probability.toFixed(1)}%</span>
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            <div className="action-buttons">
                <button className="btn-primary" onClick={onReset}>Check Another Symptom</button>
                <Link to="/history" className="btn-secondary">View History</Link>
            </div>

            <div className="disclaimer">
                <small>⚠️ <strong>Medical Disclaimer:</strong> This is an AI prediction tool and should not replace professional medical advice. Please consult a healthcare provider for accurate diagnosis.</small>
            </div>
        </div>
    );
};

// ==================== History Page ====================
const History = () => {
    const [history, setHistory] = useState([]);

    useEffect(() => {
        api.get('/history').then(res => setHistory(res.data.data || []));
    }, []);

    return (
        <div className="history-container">
            <div className="card">
                <h2>📜 Prediction History</h2>
                {history.length === 0 ? (
                    <p className="empty-state">No predictions yet. Start by checking your symptoms!</p>
                ) : (
                    <div className="history-list">
                        {history.map(item => (
                            <div key={item._id} className="history-item">
                                <div className="history-header">
                                    <h3>{item.predictedDisease}</h3>
                                    <span className="confidence">{item.confidence.toFixed(1)}%</span>
                                </div>
                                <p className="timestamp">{new Date(item.timestamp).toLocaleString()}</p>
                                <div className="symptoms-list">
                                    {item.symptoms.slice(0, 5).map((s, idx) => (
                                        <span key={idx} className="symptom-tag">{s.replace(/_/g, ' ')}</span>
                                    ))}
                                    {item.symptoms.length > 5 && <span>+{item.symptoms.length - 5} more</span>}
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
};

// ==================== Navigation ====================
const Navigation = () => {
    const { user, logout } = useAuth();
    const navigate = useNavigate();

    const handleLogout = () => {
        logout();
        navigate('/login');
    };

    return (
        <nav className="navbar">
            <div className="nav-brand">
                <span className="logo">🏥</span>
                <span className="brand-name">Disease Predictor</span>
            </div>
            {user && (
                <div className="nav-links">
                    <Link to="/">Check Symptoms</Link>
                    <Link to="/history">History</Link>
                    <span className="user-name">{user.name}</span>
                    <button onClick={handleLogout} className="btn-logout">Logout</button>
                </div>
            )}
        </nav>
    );
};

// ==================== Protected Route ====================
const ProtectedRoute = ({ children }) => {
    const { user, loading } = useAuth();
    if (loading) return <div className="loading">Loading...</div>;
    return user ? children : <Navigate to="/login" />;
};

// ==================== Main App ====================
function App() {
    return (
        <AuthProvider>
            <BrowserRouter>
                <div className="app">
                    <Navigation />
                    <div className="container">
                        <Routes>
                            <Route path="/login" element={<Login />} />
                            <Route path="/register" element={<Register />} />
                            <Route path="/" element={<ProtectedRoute><SymptomChecker /></ProtectedRoute>} />
                            <Route path="/history" element={<ProtectedRoute><History /></ProtectedRoute>} />
                        </Routes>
                    </div>
                </div>
            </BrowserRouter>
        </AuthProvider>
    );
}

export default App;
